body.script:
    var CATEGORIES = [
      { id: "technical", label: "Technical" },
      { id: "programme", label: "Programme" },
      { id: "scope", label: "Scope" },
      { id: "rfi", label: "RFI" },
      { id: "site", label: "Site Issue" },
      { id: "general", label: "General" },
    ];

    var TONES = [
      { id: "friendly", label: "Friendly" },
      { id: "firm", label: "Firm & Direct" },
      { id: "collaborative", label: "Collaborative" },
    ];

    var SYSTEM_PROMPT = "You are an AI email assistant for Adrian Natonek, Structural Engineer at Speedeck Foundations in the UK.\n\nROLE CONTEXT:\n- Name: Adrian Natonek MTech(Hons) CEng\n- Position: Structural Engineer, Team lead / coordination\n- Company: SPEEDECK Foundations Ltd. (subcontractor for foundations and ground-related structures)\n- Team: 9 engineers\n- Responsibilities: structural design, verification, foundations, technical coordination with main contractor/client, reviewing drawings/specs, managing team workload, resolving site issues, programme alignment, risk identification\n\nWRITING STYLE (MANDATORY):\n- B2-level UK English (clear, not overly complex vocabulary)\n- Friendly but professional\n- Structured and practical\n- Decision-oriented - always move things forward\n- Concise but complete\n- No unnecessary corporate jargon\n- Use UK spelling (e.g. programme, behaviour, colour)\n- Be commercially aware when needed but don't be aggressive\n\nEMAIL FORMAT (MANDATORY):\n- Font: Aptos (Body), size 12\n- Start with a greeting like \"Hi [Name],\" or \"Dear [Name],\" based on the incoming email\n- Write the body text in clear paragraphs\n- DO NOT include any signature block in the response. The signature is added automatically by Outlook. End the email body right after the last paragraph of content. Do NOT write \"Kind regards\" or any sign-off — Outlook handles this.\n\nYou must respond ONLY with a valid JSON object. No markdown, no backticks, no preamble. The JSON must have this structure:\n{\"responses\": [{\"label\": \"Short 2-4 word label describing approach\", \"body\": \"The email body text ONLY - no signature\", \"notes\": \"Brief note on when to use this option\"}]}\n\nGenerate exactly 3 response options with different strategic approaches.";

    var ACCENT_BG = ["#EFF6FC", "#F0FFF0", "#FFF8E5"];
    var ACCENT_FG = ["#0078D4", "#107C10", "#CA5010"];

    var selectedCategory = "technical";
    var selectedTone = "friendly";
    var emailBody = "";
    var emailSubject = "";
    var openCard = null;

    Office.onReady(function(info) {
      if (info.host === Office.HostType.Outlook) {
        loadEmail();
        showStatus("Connected to Outlook", true);
      }
    });

    function loadEmail() {
      try {
        var item = Office.context.mailbox.item;
        emailSubject = item.subject || "";

        item.body.getAsync(Office.CoercionType.Text, function(result) {
          if (result.status === Office.AsyncResultStatus.Succeeded) {
            emailBody = result.value.trim();
            var preview = document.getElementById("emailPreview");
            if (emailBody) {
              preview.textContent = emailBody.substring(0, 500) + (emailBody.length > 500 ? "..." : "");
              preview.classList.add("has-content");
              document.getElementById("btnGenerate").disabled = false;
            } else {
              preview.textContent = "No email body found.";
            }
          }
        });
      } catch (e) {
        showStatus("Could not read email: " + e.message, false);
      }
    }

    function showStatus(text, ok) {
      var bar = document.getElementById("status-bar");
      var dot = document.getElementById("status-dot");
      var txt = document.getElementById("status-text");
      bar.style.display = "flex";
      dot.className = "status-dot " + (ok ? "ok" : "err");
      txt.textContent = text;
    }

    function renderChips(containerId, items, selectedId, onSelect) {
      var el = document.getElementById(containerId);
      el.innerHTML = "";
      items.forEach(function(item) {
        var chip = document.createElement("button");
        chip.className = "chip" + (item.id === selectedId ? " active" : "");
        chip.textContent = item.label;
        chip.onclick = function() {
          onSelect(item.id);
          renderChips(containerId, items, item.id, onSelect);
        };
        el.appendChild(chip);
      });
    }

    renderChips("categoryChips", CATEGORIES, selectedCategory, function(id) { selectedCategory = id; });
    renderChips("toneChips", TONES, selectedTone, function(id) { selectedTone = id; });

    document.getElementById("btnGenerate").onclick = async function() {
      var apiKey = document.getElementById("apiKey").value.trim();
      if (!apiKey) {
        showError("Please enter your Anthropic API key above.");
        return;
      }
      if (!emailBody) {
        showError("No email content loaded.");
        return;
      }

      var btn = document.getElementById("btnGenerate");
      var loading = document.getElementById("loading");
      var results = document.getElementById("results");

      btn.disabled = true;
      btn.textContent = "Generating...";
      loading.style.display = "flex";
      results.innerHTML = "";
      hideError();

      var catLabel = CATEGORIES.find(function(c) { return c.id === selectedCategory; }).label;
      var toneLabel = TONES.find(function(t) { return t.id === selectedTone; }).label;

      try {
        var res = await fetch("https://api.anthropic.com/v1/messages", {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
            "x-api-key": apiKey,
            "anthropic-version": "2023-06-01",
            "anthropic-dangerous-direct-browser-access": "true"
          },
          body: JSON.stringify({
            model: "claude-sonnet-4-20250514",
            max_tokens: 1500,
            system: SYSTEM_PROMPT,
            messages: [
              {
                role: "user",
                content: "Subject: " + emailSubject + "\nCategory: " + catLabel + "\nPreferred tone: " + toneLabel + "\n\nIncoming email:\n---\n" + emailBody + "\n---\n\nGenerate 3 response options. Remember: body text only, NO signature block, NO 'Kind regards' — Outlook adds the signature automatically."
              }
            ]
          })
        });

        var data = await res.json();

        if (data.error) {
          throw new Error(data.error.message || "API error");
        }

        var text = data.content.map(function(b) { return b.text || ""; }).join("");
        var clean = text.replace(/```json|```/g, "").trim();
        var parsed = JSON.parse(clean);

        renderResults(parsed.responses);
      } catch (e) {
        showError("Error: " + e.message);
      } finally {
        btn.disabled = false;
        btn.textContent = "Generate Response Options";
        loading.style.display = "none";
      }
    };

    function renderResults(responses) {
      var container = document.getElementById("results");
      container.innerHTML = "";
      openCard = null;

      responses.forEach(function(r, i) {
        var card = document.createElement("div");
        card.className = "response-card";
        card.id = "card-" + i;

        var header = document.createElement("button");
        header.className = "card-header";
        header.innerHTML =
          '
' + (i + 1) + '' +
          '

' + escHtml(r.label) + '' +
          '
' + escHtml(r.notes) + '' +
          '▾';

        header.onclick = function() { toggleCard(i); };
        card.appendChild(header);

        var body = document.createElement("div");
        body.className = "card-body";
        body.id = "body-" + i;
        body.style.display = "none";

        var textDiv = document.createElement("div");
        textDiv.className = "response-text";
        textDiv.textContent = r.body;
        body.appendChild(textDiv);

        var btnRow = document.createElement("div");
        btnRow.className = "btn-row";

        var copyBtn = document.createElement("button");
        copyBtn.className = "btn-copy";
        copyBtn.id = "copy-" + i;
        copyBtn.textContent = "Copy";
        copyBtn.onclick = function(e) {
          e.stopPropagation();
          copyText(r.body, i);
        };

        var insertBtn = document.createElement("button");
        insertBtn.className = "btn-insert";
        insertBtn.textContent = "Insert as Reply";
        insertBtn.onclick = function(e) {
          e.stopPropagation();
          insertReply(r.body);
        };

        btnRow.appendChild(copyBtn);
        btnRow.appendChild(insertBtn);
        body.appendChild(btnRow);
        card.appendChild(body);
        container.appendChild(card);
      });
    }

    function toggleCard(i) {
      var body = document.getElementById("body-" + i);
      var arrow = document.getElementById("arrow-" + i);
      var card = document.getElementById("card-" + i);

      if (openCard === i) {
        body.style.display = "none";
        arrow.classList.remove("open");
        card.classList.remove("open");
        openCard = null;
      } else {
        if (openCard !== null) {
          document.getElementById("body-" + openCard).style.display = "none";
          document.getElementById("arrow-" + openCard).classList.remove("open");
          document.getElementById("card-" + openCard).classList.remove("open");
        }
        body.style.display = "block";
        arrow.classList.add("open");
        card.classList.add("open");
        openCard = i;
      }
    }

    function copyText(text, i) {
      navigator.clipboard.writeText(text).then(function() {
        var btn = document.getElementById("copy-" + i);
        btn.textContent = "Copied!";
        btn.classList.add("copied");
        setTimeout(function() {
          btn.textContent = "Copy";
          btn.classList.remove("copied");
        }, 2000);
      });
    }

    function insertReply(text) {
      try {
        Office.context.mailbox.item.displayReplyForm(text);
        showStatus("Reply form opened!", true);
      } catch (e) {
        showStatus("Could not open reply: " + e.message, false);
      }
    }

    function showError(msg) {
      var el = document.getElementById("error");
      el.textContent = msg;
      el.style.display = "block";
    }

    function hideError() {
      document.getElementById("error").style.display = "none";
    }

    function escHtml(s) {
      var d = document.createElement("div");
      d.textContent = s;
      return d.innerHTML;
    }
